import{_ as n}from"./plugin-vue_export-helper-c27b6911.js";import{o as s,c as a,e as t}from"./app-91868754.js";const e={},p=t(`<h2 id="_1-ajax란" tabindex="-1"><a class="header-anchor" href="#_1-ajax란" aria-hidden="true">#</a> 1. Ajax란?</h2><p>Ajax(Asynchronous JavaScript and XML)란 자바스크립트를 사용하여 브라우저가 서버에게<br> 비동기 방식으로 데이터를 요청하고, 서버가 응답한 데이터를 수신하여 웹페이지를 동적으로 갱신하는 프로그래밍 방식을 말한다.</p><p>이전의 웹페이지는 html 태그로 시작해서 html 태그로 끝나는 완전한 HTML을 서버로부터 전송받아<br> 웹페이지 전체를 처음부터 다시 렌더링하는 방식으로 동작했다.</p><figure><img src="https://github.com/Zamoca42/blog/assets/96982072/6809cb8f-8cde-4bae-b477-92eb7354d228" alt="그림 43-1. 전통적인 웹페이지의 생명 주기" tabindex="0" loading="lazy"><figcaption>그림 43-1. 전통적인 웹페이지의 생명 주기</figcaption></figure><p>이러한 전통적인 방식은 다음과 같은 단점이 있다.</p><ol><li>HTML을 서버로부터 매번 다시 전송받기 때문에 불필요한 데이터 통신이 발생한다.</li><li>변경할 필요가 없는 부분까지 처음부터 다시 렌더링한다.</li><li>서버로부터 응답이 있을 때까지 다음 처리는 블로킹된다.</li></ol><figure><img src="https://github.com/Zamoca42/blog/assets/96982072/edaec104-e897-48e9-8e84-6b4c3610396f" alt="그림 43-2. Ajax" tabindex="0" loading="lazy"><figcaption>그림 43-2. Ajax</figcaption></figure><p>Ajax는 전통적인 방식과 비교했을 때 다음과 같은 장점이 있다.</p><ol><li>필요한 데이터만 서버로부터 전송받기 때 불필요한 데이터 통신이 발생하지 않는다.</li><li>변경할 필요가 없는 부분은 다시 렌더링하지 않는다.</li><li>비동기 방식으로 동작하기 때문에 서버에게 요청을 보낸 이후 블로킹이 발생하지 않는다.</li></ol><h2 id="_2-json" tabindex="-1"><a class="header-anchor" href="#_2-json" aria-hidden="true">#</a> 2. JSON</h2><p>JSON은 클라이언트와 서버 간의 HTTP 통신을 위한 텍스트 데이터 포맷이다.<br> 자바스크립트에 종속되지 않는 언어 독립형 데이터 포맷으로, 대부분의 프로그래밍 언어에서 사용할 수 있다.</p><h3 id="_2-1-json-표기-방식" tabindex="-1"><a class="header-anchor" href="#_2-1-json-표기-방식" aria-hidden="true">#</a> 2.1. JSON 표기 방식</h3><p>JSON은 자바스크립트의 객체 리터럴과 유사하게 키와 값으로 구성된 순수한 텍스트다.</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token punctuation">{</span>
  <span class="token string-property property">&quot;name&quot;</span><span class="token operator">:</span> <span class="token string">&quot;Lee&quot;</span><span class="token punctuation">,</span>
  <span class="token string-property property">&quot;age&quot;</span><span class="token operator">:</span> <span class="token number">20</span><span class="token punctuation">,</span>
  <span class="token string-property property">&quot;alive&quot;</span><span class="token operator">:</span> <span class="token boolean">true</span><span class="token punctuation">,</span>
  <span class="token string-property property">&quot;hobby&quot;</span><span class="token operator">:</span> <span class="token punctuation">[</span><span class="token string">&quot;traveling&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;tennis&quot;</span><span class="token punctuation">]</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>JSON의 키는 반드시 큰따옴표(작은따옴표 사용 불가)로 묶어야 한다.<br> 값은 객체 리터럴과 같은 표기법을 그대로 사용할 수 있다.<br> 하지만 문자열은 반드시 큰 따옴표(작은따옴표 사용 불가)로 묶어야 한다.</p><h3 id="_2-2-json-stringify" tabindex="-1"><a class="header-anchor" href="#_2-2-json-stringify" aria-hidden="true">#</a> 2.2. JSON.stringify</h3><p>JSON.stringify 메서드는 객체를 JSON 포맷의 문자열로 변환한다.<br> 클라이언트가 서버로 객체를 전송하려면 객체를 문자열화해야하는데 이를 직렬화라 한다.</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token keyword">const</span> obj <span class="token operator">=</span> <span class="token punctuation">{</span>
  <span class="token literal-property property">name</span><span class="token operator">:</span> <span class="token string">&quot;Lee&quot;</span><span class="token punctuation">,</span>
  <span class="token literal-property property">age</span><span class="token operator">:</span> <span class="token number">20</span><span class="token punctuation">,</span>
  <span class="token literal-property property">alive</span><span class="token operator">:</span> <span class="token boolean">true</span><span class="token punctuation">,</span>
  <span class="token literal-property property">hobby</span><span class="token operator">:</span> <span class="token punctuation">[</span><span class="token string">&quot;traveling&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;tennis&quot;</span><span class="token punctuation">]</span><span class="token punctuation">,</span>
<span class="token punctuation">}</span><span class="token punctuation">;</span>

<span class="token comment">// 객체를 JSON 포맷의 문자열로 변환한다.</span>
<span class="token keyword">const</span> json <span class="token operator">=</span> <span class="token constant">JSON</span><span class="token punctuation">.</span><span class="token function">stringify</span><span class="token punctuation">(</span>obj<span class="token punctuation">)</span><span class="token punctuation">;</span>
console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span><span class="token keyword">typeof</span> json<span class="token punctuation">,</span> json<span class="token punctuation">)</span><span class="token punctuation">;</span>
<span class="token comment">// string {&quot;name&quot;:&quot;Lee&quot;,&quot;age&quot;:20,&quot;alive&quot;:true,&quot;hobby&quot;:[&quot;traveling&quot;,&quot;tennis&quot;]}</span>

<span class="token comment">// 객체를 JSON 포맷의 문자열로 변환하면서 들여쓰기 한다.</span>
<span class="token keyword">const</span> prettyJson <span class="token operator">=</span> <span class="token constant">JSON</span><span class="token punctuation">.</span><span class="token function">stringify</span><span class="token punctuation">(</span>obj<span class="token punctuation">,</span> <span class="token keyword">null</span><span class="token punctuation">,</span> <span class="token number">2</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span><span class="token keyword">typeof</span> prettyJson<span class="token punctuation">,</span> prettyJson<span class="token punctuation">)</span><span class="token punctuation">;</span>
<span class="token comment">/*
string {
  &quot;name&quot;: &quot;Lee&quot;,
  &quot;age&quot;: 20,
  &quot;alive&quot;: true,
  &quot;hobby&quot;: [
    &quot;traveling&quot;,
    &quot;tennis&quot;
  ]
}
*/</span>

<span class="token comment">// replacer 함수. 값의 타입이 Number이면 필터링되어 반환되지 않는다.</span>
<span class="token keyword">function</span> <span class="token function">filter</span><span class="token punctuation">(</span><span class="token parameter">key<span class="token punctuation">,</span> value</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
  <span class="token comment">// undefined: 반환하지 않음</span>
  <span class="token keyword">return</span> <span class="token keyword">typeof</span> value <span class="token operator">===</span> <span class="token string">&quot;number&quot;</span> <span class="token operator">?</span> <span class="token keyword">undefined</span> <span class="token operator">:</span> value<span class="token punctuation">;</span>
<span class="token punctuation">}</span>

<span class="token comment">// JSON.stringify 메서드에 두 번째 인수로 replacer 함수를 전달한다.</span>
<span class="token keyword">const</span> strFilteredObject <span class="token operator">=</span> <span class="token constant">JSON</span><span class="token punctuation">.</span><span class="token function">stringify</span><span class="token punctuation">(</span>obj<span class="token punctuation">,</span> filter<span class="token punctuation">,</span> <span class="token number">2</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span><span class="token keyword">typeof</span> strFilteredObject<span class="token punctuation">,</span> strFilteredObject<span class="token punctuation">)</span><span class="token punctuation">;</span>
<span class="token comment">/*
string {
  &quot;name&quot;: &quot;Lee&quot;,
  &quot;alive&quot;: true,
  &quot;hobby&quot;: [
    &quot;traveling&quot;,
    &quot;tennis&quot;
  ]
}
*/</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>JSON.stringify 메서드는 객체뿐만 아니라 배열도 JSON 포맷의 문자열로 변환한다.</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token keyword">const</span> todos <span class="token operator">=</span> <span class="token punctuation">[</span>
  <span class="token punctuation">{</span> <span class="token literal-property property">id</span><span class="token operator">:</span> <span class="token number">1</span><span class="token punctuation">,</span> <span class="token literal-property property">content</span><span class="token operator">:</span> <span class="token string">&quot;HTML&quot;</span><span class="token punctuation">,</span> <span class="token literal-property property">completed</span><span class="token operator">:</span> <span class="token boolean">false</span> <span class="token punctuation">}</span><span class="token punctuation">,</span>
  <span class="token punctuation">{</span> <span class="token literal-property property">id</span><span class="token operator">:</span> <span class="token number">2</span><span class="token punctuation">,</span> <span class="token literal-property property">content</span><span class="token operator">:</span> <span class="token string">&quot;CSS&quot;</span><span class="token punctuation">,</span> <span class="token literal-property property">completed</span><span class="token operator">:</span> <span class="token boolean">true</span> <span class="token punctuation">}</span><span class="token punctuation">,</span>
  <span class="token punctuation">{</span> <span class="token literal-property property">id</span><span class="token operator">:</span> <span class="token number">3</span><span class="token punctuation">,</span> <span class="token literal-property property">content</span><span class="token operator">:</span> <span class="token string">&quot;Javascript&quot;</span><span class="token punctuation">,</span> <span class="token literal-property property">completed</span><span class="token operator">:</span> <span class="token boolean">false</span> <span class="token punctuation">}</span><span class="token punctuation">,</span>
<span class="token punctuation">]</span><span class="token punctuation">;</span>

<span class="token comment">// 배열을 JSON 포맷의 문자열로 변환한다.</span>
<span class="token keyword">const</span> json <span class="token operator">=</span> <span class="token constant">JSON</span><span class="token punctuation">.</span><span class="token function">stringify</span><span class="token punctuation">(</span>todos<span class="token punctuation">,</span> <span class="token keyword">null</span><span class="token punctuation">,</span> <span class="token number">2</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span><span class="token keyword">typeof</span> json<span class="token punctuation">,</span> json<span class="token punctuation">)</span><span class="token punctuation">;</span>
<span class="token comment">/*
string [
  {
    &quot;id&quot;: 1,
    &quot;content&quot;: &quot;HTML&quot;,
    &quot;completed&quot;: false
  },
  {
    &quot;id&quot;: 2,
    &quot;content&quot;: &quot;CSS&quot;,
    &quot;completed&quot;: true
  },
  {
    &quot;id&quot;: 3,
    &quot;content&quot;: &quot;Javascript&quot;,
    &quot;completed&quot;: false
  }
]
*/</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="_2-3-json-parse" tabindex="-1"><a class="header-anchor" href="#_2-3-json-parse" aria-hidden="true">#</a> 2.3. JSON.parse</h3><p>JSON.parse 메서드는 JSON 포맷의 문자열을 객체로 변환한다.<br> 서버로부터 클라이언트에게 전송된 JSON 데이터는 문자열이다.<br> 이 문자열을 객체로서 사용하려면 JSON 포맷의 문자열을 객체화해야 하는데 이를 역직렬화라 한다.</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token keyword">const</span> obj <span class="token operator">=</span> <span class="token punctuation">{</span>
  <span class="token literal-property property">name</span><span class="token operator">:</span> <span class="token string">&quot;Lee&quot;</span><span class="token punctuation">,</span>
  <span class="token literal-property property">age</span><span class="token operator">:</span> <span class="token number">20</span><span class="token punctuation">,</span>
  <span class="token literal-property property">alive</span><span class="token operator">:</span> <span class="token boolean">true</span><span class="token punctuation">,</span>
  <span class="token literal-property property">hobby</span><span class="token operator">:</span> <span class="token punctuation">[</span><span class="token string">&quot;traveling&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;tennis&quot;</span><span class="token punctuation">]</span><span class="token punctuation">,</span>
<span class="token punctuation">}</span><span class="token punctuation">;</span>

<span class="token comment">// 객체를 JSON 포맷의 문자열로 변환한다.</span>
<span class="token keyword">const</span> json <span class="token operator">=</span> <span class="token constant">JSON</span><span class="token punctuation">.</span><span class="token function">stringify</span><span class="token punctuation">(</span>obj<span class="token punctuation">)</span><span class="token punctuation">;</span>

<span class="token comment">// JSON 포맷의 문자열을 객체로 변환한다.</span>
<span class="token keyword">const</span> parsed <span class="token operator">=</span> <span class="token constant">JSON</span><span class="token punctuation">.</span><span class="token function">parse</span><span class="token punctuation">(</span>json<span class="token punctuation">)</span><span class="token punctuation">;</span>
console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span><span class="token keyword">typeof</span> parsed<span class="token punctuation">,</span> parsed<span class="token punctuation">)</span><span class="token punctuation">;</span>
<span class="token comment">// object {name: &quot;Lee&quot;, age: 20, alive: true, hobby: [&quot;traveling&quot;, &quot;tennis&quot;]}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>배열이 JSON 포맷의 문자열로 변환되어 있는 경우 JSON.parse는 문자열을 배열 객체로 변환한다.</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token keyword">const</span> todos <span class="token operator">=</span> <span class="token punctuation">[</span>
  <span class="token punctuation">{</span> <span class="token literal-property property">id</span><span class="token operator">:</span> <span class="token number">1</span><span class="token punctuation">,</span> <span class="token literal-property property">content</span><span class="token operator">:</span> <span class="token string">&quot;HTML&quot;</span><span class="token punctuation">,</span> <span class="token literal-property property">completed</span><span class="token operator">:</span> <span class="token boolean">false</span> <span class="token punctuation">}</span><span class="token punctuation">,</span>
  <span class="token punctuation">{</span> <span class="token literal-property property">id</span><span class="token operator">:</span> <span class="token number">2</span><span class="token punctuation">,</span> <span class="token literal-property property">content</span><span class="token operator">:</span> <span class="token string">&quot;CSS&quot;</span><span class="token punctuation">,</span> <span class="token literal-property property">completed</span><span class="token operator">:</span> <span class="token boolean">true</span> <span class="token punctuation">}</span><span class="token punctuation">,</span>
  <span class="token punctuation">{</span> <span class="token literal-property property">id</span><span class="token operator">:</span> <span class="token number">3</span><span class="token punctuation">,</span> <span class="token literal-property property">content</span><span class="token operator">:</span> <span class="token string">&quot;Javascript&quot;</span><span class="token punctuation">,</span> <span class="token literal-property property">completed</span><span class="token operator">:</span> <span class="token boolean">false</span> <span class="token punctuation">}</span><span class="token punctuation">,</span>
<span class="token punctuation">]</span><span class="token punctuation">;</span>

<span class="token comment">// 배열을 JSON 포맷의 문자열로 변환한다.</span>
<span class="token keyword">const</span> json <span class="token operator">=</span> <span class="token constant">JSON</span><span class="token punctuation">.</span><span class="token function">stringify</span><span class="token punctuation">(</span>todos<span class="token punctuation">)</span><span class="token punctuation">;</span>

<span class="token comment">// JSON 포맷의 문자열을 배열로 변환한다. 배열의 요소까지 객체로 변환된다.</span>
<span class="token keyword">const</span> parsed <span class="token operator">=</span> <span class="token constant">JSON</span><span class="token punctuation">.</span><span class="token function">parse</span><span class="token punctuation">(</span>json<span class="token punctuation">)</span><span class="token punctuation">;</span>
console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span><span class="token keyword">typeof</span> parsed<span class="token punctuation">,</span> parsed<span class="token punctuation">)</span><span class="token punctuation">;</span>
<span class="token comment">/*
 object [
  { id: 1, content: &#39;HTML&#39;, completed: false },
  { id: 2, content: &#39;CSS&#39;, completed: true },
  { id: 3, content: &#39;Javascript&#39;, completed: false }
]
*/</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="_3-xmlhttprequest" tabindex="-1"><a class="header-anchor" href="#_3-xmlhttprequest" aria-hidden="true">#</a> 3. XMLHttpRequest</h2><p>Web API인 XMLHttpRequest 객체는 HTTP 요청 전송과 HTTP 응답 수신을 위한 다양한 메서드와 프로퍼티를 제공한다.</p><h3 id="_3-1-xmlhttprequest-객체-생성" tabindex="-1"><a class="header-anchor" href="#_3-1-xmlhttprequest-객체-생성" aria-hidden="true">#</a> 3.1. XMLHttpRequest 객체 생성</h3><p>XMLHttpRequest 객체는 생성자 함수를 호출하여 생성한다.<br> 브라우저에서 제공하는 Web API이므로 브라우저 환경에서만 정상적으로 실행된다.</p><h3 id="_3-2-xmlhttprequest-객체의-프로퍼티와-메서드" tabindex="-1"><a class="header-anchor" href="#_3-2-xmlhttprequest-객체의-프로퍼티와-메서드" aria-hidden="true">#</a> 3.2. XMLHttpRequest 객체의 프로퍼티와 메서드</h3><p>대표적인 프로퍼티와 메서드는 다음과 같다.</p><h4 id="xmlhttprequest-객체의-프로토타입-프로퍼티" tabindex="-1"><a class="header-anchor" href="#xmlhttprequest-객체의-프로토타입-프로퍼티" aria-hidden="true">#</a> XMLHttpRequest 객체의 프로토타입 프로퍼티</h4><ul><li><p>readyState</p><ul><li>HTTP 요청의 현재 상태를 나타내는 정수 <ul><li>UNSENT: 0</li><li>OPENED: 1</li><li>HEADERS_RECEIVED: 2</li><li>LOADING: 3</li><li>DONE: 4</li></ul></li></ul></li><li><p>status</p><ul><li>HTTP 요청에 대한 응답 상태를 나타내는 정수 (예 - 200)</li></ul></li><li><p>statusText</p><ul><li>HTTP 요청에 대한 응답 메세지 (예 - &quot;OK&quot;)</li></ul></li><li><p>responseType</p><ul><li>HTTP 응답 타입</li></ul></li><li><p>response</p><ul><li>HTTP 요청에 대한 응답 몸체(body)</li></ul></li><li><p>responseText</p><ul><li>서버가 전송한 HTTP 요청에 대한 응답 문자열</li></ul></li></ul><h3 id="_3-3-http-요청-전송" tabindex="-1"><a class="header-anchor" href="#_3-3-http-요청-전송" aria-hidden="true">#</a> 3.3. HTTP 요청 전송</h3><p>HTTP 요청을 전송하는 경우 다음 순서를 따른다.</p><ol><li>XMLHttpRequest.prototype.open 메서드로 HTTP 요청을 초기화한다.</li><li>필요에 따라 XMLHttpRequest.prototype.setRequestHeader 메서드로 특정 HTTP 요청의 헤더 값을 설정</li><li>XMLHttpRequest.prototype.send 메서드로 HTTP 요청을 전송한다.</li></ol><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token comment">// XMLHttpRequest 객체 생성</span>
<span class="token keyword">const</span> xhr <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">XMLHttpRequest</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>

<span class="token comment">// HTTP 요청 초기화</span>
xhr<span class="token punctuation">.</span><span class="token function">open</span><span class="token punctuation">(</span><span class="token string">&#39;GET&#39;</span><span class="token punctuation">,</span> <span class="token string">&#39;/users&#39;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>

<span class="token comment">// HTTP 요청 헤더 설정</span>
<span class="token comment">// 클라이언트가 서버로 전송할 데이터의 MIME 타입 지정: json</span>
xhr<span class="token punctuation">.</span><span class="token function">setRequestHeader</span><span class="token punctuation">(</span><span class="token string">&#39;content-type&#39;</span><span class="token punctuation">,</span> <span class="token string">&#39;application/json&#39;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>

<span class="token comment">// HTTP 요청 전송</span>
xhr<span class="token punctuation">.</span><span class="token function">send</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><figure><img src="https://github.com/Zamoca42/blog/assets/96982072/508716ae-097f-4b1b-b8c3-7bc9399a7492" alt="그림 43-3. HTTP 요청/응답 메시지" tabindex="0" loading="lazy"><figcaption>그림 43-3. HTTP 요청/응답 메시지</figcaption></figure>`,38),o=[p];function l(i,c){return s(),a("div",null,o)}const d=n(e,[["render",l],["__file","deepdive43.html.vue"]]);export{d as default};
